import{c as a,Q as o,j as t,m as r}from"./chunks/framework.CPTW7DhK.js";const p=JSON.parse('{"title":"Requisitos de Hardware e Software — Easy Web / Light Web / 3.0 Web","description":"Guia de preparação do ambiente para o Desbravador Easy Web, Light Web e 3.0 Web","frontmatter":{"title":"Requisitos de Hardware e Software — Easy Web / Light Web / 3.0 Web","description":"Guia de preparação do ambiente para o Desbravador Easy Web, Light Web e 3.0 Web","system":"Desbravador Easy Web / Light Web / 3.0 Web","modality":"SaaS / Online","audience":"Cliente / Equipe de TI"},"headers":[],"relativePath":"light-web/local/requisitos-hardware.md","filePath":"light-web/local/requisitos-hardware.md","lastUpdated":null}'),i={name:"light-web/local/requisitos-hardware.md"};function s(d,e,n,l,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="requisitos-de-hardware-—-easy-web-light-web-3-0-web" tabindex="-1">Requisitos de Hardware — Easy Web / Light Web / 3.0 Web <a class="header-anchor" href="#requisitos-de-hardware-—-easy-web-light-web-3-0-web" aria-label="Permalink to &quot;Requisitos de Hardware — Easy Web / Light Web / 3.0 Web&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador Easy Web / Light Web / 3.0 Web<br><strong>Modalidade:</strong> SaaS / Online<br><strong>Público:</strong> Cliente / Equipe de TI</p><hr><h2 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Descrição</th><th>Responsável</th></tr></thead><tbody><tr><td>1.0</td><td>Mai/2026</td><td>Criação do documento</td><td>Desbravador Software Ltda.</td></tr><tr><td>1.1</td><td>Mai/2026</td><td>Inclusão de versões mínimas de navegador, requisitos de CPU 64-bit e faixas de internet</td><td>Desbravador Software Ltda.</td></tr></tbody></table><hr><h2 id="consideracoes-iniciais" tabindex="-1">Considerações Iniciais <a class="header-anchor" href="#consideracoes-iniciais" aria-label="Permalink to &quot;Considerações Iniciais&quot;">​</a></h2><p>O Desbravador Easy Web, Light Web e 3.0 Web são sistemas 100% online, acessados exclusivamente via navegador web — não há instalação de software nas estações de trabalho.</p><blockquote><p>ℹ️ O sistema funciona via navegador em qualquer sistema operacional. Windows é obrigatório apenas no computador com conexão física à central telefônica, impressoras fiscais ou emissão de notas eletrônicas.</p></blockquote><p>Demais pontos relevantes antes da implantação:</p><ul><li>Relatórios são gerados em formato PDF — todas as estações de acesso devem ter um leitor de PDF instalado (o próprio Chrome atende esse requisito nativamente).</li><li>Nobreak é recomendado em todos os computadores para evitar contratempos por quedas de energia.</li><li>Antivírus instalado e atualizado é obrigatório.</li><li>Durante o treinamento online, é essencial a disponibilidade e participação ativa dos usuários responsáveis pela operação do sistema.</li></ul><hr><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este documento serve como guia para a preparação do ambiente de funcionamento do Desbravador Easy Web, Light Web e 3.0 Web, abordando os requisitos técnicos de hardware, software, rede e integrações necessários para operação do sistema.</p><p>Por ser uma plataforma SaaS, não há servidor local de banco de dados nem de aplicação a provisionar. Os requisitos se concentram nas estações de acesso, na qualidade da conexão com a internet e nos equipamentos de integração física, quando aplicável.</p><hr><h2 id="_2-responsabilidades" tabindex="-1">2. Responsabilidades <a class="header-anchor" href="#_2-responsabilidades" aria-label="Permalink to &quot;2. Responsabilidades&quot;">​</a></h2><h3 id="_2-1-desbravador-software-ltda" tabindex="-1">2.1 Desbravador Software Ltda. <a class="header-anchor" href="#_2-1-desbravador-software-ltda" aria-label="Permalink to &quot;2.1 Desbravador Software Ltda.&quot;">​</a></h3><ul><li>A instalação e configuração dos componentes de integração (coleta de bilhetes, emissão de notas eletrônicas) é realizada exclusivamente pelo Analista de Implantação da Desbravador.</li><li>O programa de coleta de bilhetes da central telefônica é fornecido pela Desbravador.</li><li>A equipe Desbravador estará disponível para esclarecer dúvidas técnicas durante todo o período de implantação.</li></ul><h3 id="_2-2-cliente-licenciado" tabindex="-1">2.2 Cliente (LICENCIADO) <a class="header-anchor" href="#_2-2-cliente-licenciado" aria-label="Permalink to &quot;2.2 Cliente (LICENCIADO)&quot;">​</a></h3><ul><li>Providenciar os equipamentos conforme as especificações deste documento.</li><li>Garantir o licenciamento dos sistemas operacionais e softwares adicionais utilizados.</li><li>Prover segurança física e lógica para os computadores de acesso e de integração.</li><li>Disponibilizar técnico de hardware durante o período de implantação.</li><li>Garantir a instalação e o cabeamento necessário para conexão de periféricos físicos (impressoras fiscais, central telefônica).</li><li>Manter antivírus instalado e atualizado em todos os equipamentos.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong></p><ul><li>A Desbravador <strong>NÃO</strong> realiza montagem/desmontagem de hardware nem instalação de sistemas operacionais.</li><li>A segurança dos arquivos e dados do sistema é responsabilidade exclusiva de quem opera o sistema.</li></ul></blockquote><hr><h2 id="_3-selecao-do-fornecedor-de-hardware" tabindex="-1">3. Seleção do Fornecedor de Hardware <a class="header-anchor" href="#_3-selecao-do-fornecedor-de-hardware" aria-label="Permalink to &quot;3. Seleção do Fornecedor de Hardware&quot;">​</a></h2><p>Ao selecionar o fornecedor de equipamentos, certifique-se de que ele oferece:</p><ul><li>Suporte técnico disponível durante o horário de operação do estabelecimento.</li><li>Garantia e assistência técnica dos equipamentos fornecidos.</li><li>Capacidade de configurar rede local, cabeamento e periféricos físicos quando necessário.</li></ul><hr><h2 id="_4-requisitos-das-estacoes-de-trabalho" tabindex="-1">4. Requisitos das Estações de Trabalho <a class="header-anchor" href="#_4-requisitos-das-estacoes-de-trabalho" aria-label="Permalink to &quot;4. Requisitos das Estações de Trabalho&quot;">​</a></h2><p>As estações de trabalho acessam o sistema exclusivamente via navegador. Não há instalação de cliente ou agente local.</p><table tabindex="0"><thead><tr><th>Item</th><th>Requisito Mínimo</th><th>Recomendado</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i3 10ª geração ou AMD Ryzen 3 equivalente (64-bit)</td><td>Intel Core i5 ou superior (64-bit)</td></tr><tr><td><strong>Memória RAM</strong></td><td>4 GB</td><td>8 GB ou mais</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 120 GB</td><td>SSD 240 GB</td></tr><tr><td><strong>Navegador</strong></td><td>Ver Seção 5</td><td>Google Chrome (última versão)</td></tr><tr><td><strong>Resolução de tela</strong></td><td>1024 × 768</td><td>1920 × 1080</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Windows 10 ou superior, licenciado</td><td>Windows 11 Pro, licenciado</td></tr><tr><td><strong>Leitor de PDF</strong></td><td>Obrigatório (o próprio Chrome atende)</td><td>Obrigatório</td></tr><tr><td><strong>Antivírus</strong></td><td>Obrigatório (instalado e atualizado)</td><td>Obrigatório (instalado e atualizado)</td></tr><tr><td><strong>Nobreak (UPS)</strong></td><td>Recomendado</td><td>Recomendado</td></tr></tbody></table><blockquote><p>ℹ️ <strong>Requisito de sistema operacional por tipo de uso</strong></p><p>A necessidade de Windows na estação de trabalho depende das integrações utilizadas:</p><ul><li><p><strong>Acesso geral ao sistema</strong> (consultas, lançamentos, relatórios) — independe de sistema operacional. Qualquer SO com navegador homologado (Chrome ou Firefox) é suficiente.</p></li><li><p><strong>Estação com integração a periféricos</strong> (fechaduras eletrônicas, TEF, impressoras fiscais ou não fiscais) — <strong>Windows obrigatório</strong>. A comunicação com esses dispositivos requer drivers e componentes exclusivos do ambiente Windows.</p></li></ul><p>Em caso de dúvida sobre o tipo de uso de cada estação, consulte a equipe Desbravador antes da aquisição dos equipamentos.</p></blockquote><hr><h2 id="_5-requisitos-de-navegador" tabindex="-1">5. Requisitos de Navegador <a class="header-anchor" href="#_5-requisitos-de-navegador" aria-label="Permalink to &quot;5. Requisitos de Navegador&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Navegador</th><th>Versão Mínima</th><th>Observação</th></tr></thead><tbody><tr><td><strong>Google Chrome</strong></td><td>120 ou superior</td><td>Recomendado — manter sempre atualizado</td></tr><tr><td><strong>Mozilla Firefox</strong></td><td>120 ou superior</td><td>Homologado</td></tr><tr><td><strong>Microsoft Edge</strong></td><td>120 ou superior</td><td>Homologado</td></tr><tr><td><strong>Apple Safari</strong></td><td>Não recomendado</td><td>Pode apresentar incompatibilidades</td></tr><tr><td><strong>Navegadores mobile</strong></td><td>Não recomendados</td><td>Uso operacional não suportado</td></tr></tbody></table><blockquote><p>ℹ️ <strong>Recomendação</strong> — Manter o navegador sempre atualizado para a última versão garante segurança, melhor desempenho e compatibilidade com todos os recursos do sistema. Em caso de dificuldade de acesso, verificar a versão do navegador é o primeiro passo de diagnóstico.</p></blockquote><hr><h2 id="_6-requisitos-de-rede-e-internet" tabindex="-1">6. Requisitos de Rede e Internet <a class="header-anchor" href="#_6-requisitos-de-rede-e-internet" aria-label="Permalink to &quot;6. Requisitos de Rede e Internet&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Mínimo</th><th>Recomendado</th></tr></thead><tbody><tr><td><strong>Velocidade de download</strong></td><td>5 Mbps</td><td>20 Mbps ou mais</td></tr><tr><td><strong>Velocidade de upload</strong></td><td>2 Mbps</td><td>10 Mbps ou mais</td></tr><tr><td><strong>Tipo de conexão</strong></td><td>Banda larga estável</td><td>Fibra óptica dedicada</td></tr><tr><td><strong>Estabilidade</strong></td><td>Crítica — ver observação abaixo</td><td>Link redundante recomendado</td></tr></tbody></table><blockquote><p>⚠️ <strong>Atenção</strong> — Por ser um sistema 100% online, a estabilidade da conexão é mais crítica do que a velocidade de pico. Uma conexão de 5 Mbps estável é preferível a uma de 50 Mbps com oscilações frequentes. Recomenda-se link dedicado com contingência (ex.: 4G como backup em caso de falha do link principal).</p></blockquote><hr><h2 id="_7-requisitos-de-software" tabindex="-1">7. Requisitos de Software <a class="header-anchor" href="#_7-requisitos-de-software" aria-label="Permalink to &quot;7. Requisitos de Software&quot;">​</a></h2><p>Os únicos softwares que requerem instalação local são os componentes de integração física, quando aplicável:</p><ul><li><strong>Navegador web:</strong> Google Chrome ou Mozilla Firefox na versão mínima indicada na Seção 5. Manter atualização automática habilitada.</li><li><strong>Leitor de PDF:</strong> obrigatório em todas as estações que gerem relatórios. O próprio Chrome atende esse requisito nativamente.</li><li><strong>Antivírus:</strong> solução licenciada, instalada e com atualização automática de definições habilitada.</li><li><strong>Componentes de integração Desbravador:</strong> instalados pelo Analista de Implantação nos computadores com conexão física a periféricos (central telefônica, impressoras fiscais, emissão de NF-e/NFC-e). Requer Windows.</li></ul><hr><h2 id="_8-central-telefonica" tabindex="-1">8. Central Telefônica <a class="header-anchor" href="#_8-central-telefonica" aria-label="Permalink to &quot;8. Central Telefônica&quot;">​</a></h2><p>O Desbravador Easy Web / Light Web / 3.0 Web integra com centrais telefônicas para coleta de bilhetes de tarifação. Requisitos:</p><ul><li>Qualquer central com bilhetagem serial ou TCP/IP pode ser integrada.</li><li>O técnico responsável deve disponibilizar o cabo de comunicação até o computador Windows mais próximo com acesso físico à central.</li><li>Nenhum programa tarifador de terceiros é necessário — o programa de coleta de bilhetes é fornecido pela Desbravador.</li><li>Consultar a Desbravador com antecedência para verificar compatibilidade com o modelo específico da central.</li></ul><blockquote><p>ℹ️ Em centrais com suporte a bilhetagem serial e TCP/IP, sempre utilizar TCP/IP.</p></blockquote><hr><h2 id="_9-e-sat-homologado" tabindex="-1">9. E-SAT Homologado <a class="header-anchor" href="#_9-e-sat-homologado" aria-label="Permalink to &quot;9. E-SAT Homologado&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fabricante</th><th>Observação</th></tr></thead><tbody><tr><td><strong>Dimep</strong></td><td>Homologado</td></tr><tr><td><strong>Bematech</strong></td><td>Homologado</td></tr></tbody></table><hr><h2 id="_10-integracao-com-notas-eletronicas-nf-e-nfc-e" tabindex="-1">10. Integração com Notas Eletrônicas (NF-e / NFC-e) <a class="header-anchor" href="#_10-integracao-com-notas-eletronicas-nf-e-nfc-e" aria-label="Permalink to &quot;10. Integração com Notas Eletrônicas (NF-e / NFC-e)&quot;">​</a></h2><p>A emissão de notas eletrônicas requer um computador com sistema operacional Windows para instalação do componente de integração da Desbravador.</p><p>Requisitos específicos para o computador de emissão:</p><ul><li>Sistema operacional Windows 10 ou superior, licenciado.</li><li>Certificado digital A1 válido (arquivo <code>.pfx</code>). Certificados A3 (token/smartcard) não são suportados.</li><li>Conexão estável com a internet, com acesso liberado aos webservices da SEFAZ.</li><li>Antivírus instalado — verificar que não bloqueia a comunicação com os serviços fiscais.</li></ul><hr><h2 id="_11-perifericos-homologados" tabindex="-1">11. Periféricos Homologados <a class="header-anchor" href="#_11-perifericos-homologados" aria-label="Permalink to &quot;11. Periféricos Homologados&quot;">​</a></h2><p>O sistema possui integração desenvolvida e homologada com os seguintes periféricos:</p><ul><li>🖨️ <a href="./../../perifericos/impressoras-homologadas.html">Impressoras fiscais e não fiscais homologadas</a></li><li>💳 <a href="./../../perifericos/pinpads-homologados.html">Pinpads homologados</a></li><li>💳 <a href="./../../perifericos/tef-homologados.html">Sistemas de TEF homologados</a></li><li>🔒 <a href="./../../perifericos/fechaduras-homologadas.html">Fechaduras e tarifadores homologados</a></li></ul><hr><h2 id="_12-observacoes-finais" tabindex="-1">12. Observações Finais <a class="header-anchor" href="#_12-observacoes-finais" aria-label="Permalink to &quot;12. Observações Finais&quot;">​</a></h2><ul><li>Por se tratar de um sistema SaaS, atualizações de versão são aplicadas automaticamente pela Desbravador, sem intervenção do cliente.</li><li>Requisitos descritos neste documento estão sujeitos a revisão conforme a evolução do produto. Consulte sempre a versão mais recente antes de iniciar uma nova implantação.</li><li>Durante o treinamento online, é essencial a disponibilidade e participação ativa dos usuários responsáveis pela operação do sistema.</li></ul><hr><h2 id="_13-contato-e-suporte" tabindex="-1">13. Contato e Suporte <a class="header-anchor" href="#_13-contato-e-suporte" aria-label="Permalink to &quot;13. Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas técnicas durante a implantação, a equipe Desbravador estará disponível para esclarecimentos.</p>',67)])])}const h=a(i,[["render",s]]);export{p as __pageData,h as default};
